# Search in hadith mats for overlaps
def get_matn_text(rec):
    return rec.get('hadithTxt') or rec.get('Matn') or ''

cands=[]
for rec in hadith:
    txt=get_matn_text(rec)
    if not txt: 
        continue
    n=normalize(txt)
    # simple substring checks for some unique words like يدع دينه, يشيع الناس, لمذكر لكم
    if any(kw in n for kw in ["يدع دينه","يشيع الناس","لمذكر لكم","اخذ بالرقبه"]):
        cands.append(txt)
len(cands)

